UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

SELECT 'CITY1' AS col, COUNT(*) AS cnt FROM decision_table WHERE CITY1 IN ('Wiblingwerde','Breckerfeld')
UNION ALL
SELECT 'CITY2' AS col, COUNT(*) AS cnt FROM decision_table WHERE CITY2 IN ('Wiblingwerde','Breckerfeld');

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
  SELECT EQUNR FROM J09C_eabl_flags
  WHERE has_ms_2023 = 1 AND has_ms_2024 = 1
);

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'DIRECT_MAIL'
WHERE EQUNR IN (
  SELECT EQUNR FROM J09C_eabl_flags
  WHERE has_dm_2023 = 1 AND has_dm_2024 = 1
)
AND EQUNR NOT IN (
  SELECT DISTINCT EQUNR FROM J09C_temp
  WHERE ENTSCHEIDUNG = 'MANDATORY_READING'
);
